#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int* A = (int*) malloc(N * sizeof(int));
        int* B = (int*) malloc(M * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < M; i++) {
            scanf("%d", &B[i]);
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (A[i] == B[j]) {
                    count++;
                    break;
                }
            }
        }
        printf("%d\n", count);
        free(A);
        free(B);
    }
    return 0;
}

