#include <iostream>
#include <set>
using namespace std;

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N, M;
        cin >> N >> M;
        set<int> A;
        set<int> B;
        for (int i = 0; i < N; i++) {
            int x;
            cin >> x;
            A.insert(x);
        }
        for (int i = 0; i < M; i++) {
            int x;
            cin >> x;
            B.insert(x);
        }
        set<int> intersection;
        for (auto it = A.begin(); it != A.end(); it++) {
            if (B.find(*it) != B.end()) {
                intersection.insert(*it);
            }
        }
        cout << intersection.size() << endl;
    }
    return 0;
}

