import java.util.Scanner;
import java.util.HashSet;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            HashSet<Integer> A = new HashSet<>();
            HashSet<Integer> B = new HashSet<>();
            for (int i = 0; i < N; i++) {
                A.add(sc.nextInt());
            }
            for (int i = 0; i < M; i++) {
                B.add(sc.nextInt());
            }
            A.retainAll(B);
            System.out.println(A.size());
        }
    }
}

